const str = '  Hello, World!  ';

console.log(str.trim());           // 'Hello, World!'
console.log(str.toLowerCase());    // '  hello, world!  '
console.log(str.includes('World')); // true
console.log(str.indexOf('World'));  // 9

const csv = 'apple,banana,cherry';
const fruits = csv.split(',');      // ['apple', 'banana', 'cherry']

const greeting = 'Hello, Alice!';
console.log(greeting.slice(7, 12)); // 'Alice'
console.log(greeting.replace('Alice', 'Bob')); // 'Hello, Bob!'

// Padding — useful for formatting
console.log('5'.padStart(3, '0')); // '005'
console.log('Hi'.padEnd(5, '.'));  // 'Hi...'

// startsWith / endsWith
console.log('filename.js'.endsWith('.js')); // true
